+/** A condition accepted by conditional option helpers. */
+export type OptionCondition = string | OptionDependency;
+
+function normalizeOptionCondition(
+  condition: OptionCondition,
+  required: boolean | undefined,
+): OptionDependency {
+  const normalized: OptionDependency = typeof condition === "string"
+    ? { option: condition }
+    : condition;
+  return required === undefined ? normalized : { ...normalized, required };
+}
+
+function conditionalOptionNames(
+  flagSpec: OptionName | readonly OptionName[],
+): readonly OptionName[] {
+  return typeof flagSpec === "string" ? [flagSpec] : flagSpec;
+}
+
+/** Creates an option required when its condition is satisfied. */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T>,
+): Parser<M, T, ValueParserResult<T> | undefined>;
+export function requiredWhen(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = conditionalOptionNames(flagSpec);
+  const options = { dependsOn: normalizeOptionCondition(condition, true) };
+  return valueParser == null
+    ? option(...names, options)
